DROP TABLE IF EXISTS `attendance_tutor`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `attendance_tutor` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `attendance_id` bigint unsigned NOT NULL,
  `tutor_id` bigint unsigned NOT NULL,
  `payable_amount` decimal(15,2) NOT NULL,
  `pending_rate` tinyint(1) NOT NULL DEFAULT '0',
  `journal_id` bigint unsigned DEFAULT NULL,
  `is_replacement` tinyint(1) NOT NULL DEFAULT '0',
  `is_team_teaching` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `paid_at` timestamp NULL DEFAULT NULL,
  `replaced_tutor_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `attendance_tutor_attendance_id_tutor_id_unique` (`attendance_id`,`tutor_id`),
  KEY `attendance_tutor_attendance_id_foreign` (`attendance_id`),
  KEY `attendance_tutor_tutor_id_foreign` (`tutor_id`),
  KEY `attendance_tutor_journal_id_foreign` (`journal_id`),
  KEY `attendance_tutor_replaced_tutor_id_foreign` (`replaced_tutor_id`),
  CONSTRAINT `attendance_tutor_attendance_id_foreign` FOREIGN KEY (`attendance_id`) REFERENCES `attendance` (`id`) ON DELETE CASCADE,
  CONSTRAINT `attendance_tutor_journal_id_foreign` FOREIGN KEY (`journal_id`) REFERENCES `journals` (`id`),
  CONSTRAINT `attendance_tutor_replaced_tutor_id_foreign` FOREIGN KEY (`replaced_tutor_id`) REFERENCES `tutors` (`id`) ON DELETE SET NULL,
  CONSTRAINT `attendance_tutor_tutor_id_foreign` FOREIGN KEY (`tutor_id`) REFERENCES `tutors` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=399 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

